import React, { useState, useEffect, useRef } from 'react';
import { SECTIONS, SOCIAL_LINKS, TRADING_STATS, SKILL_DATA, PROJECTS_DATA } from './constants';
import Navigation from './components/Navigation';
import Section from './components/Section';
import SocialCard from './components/SocialCard';
import ProjectCard from './components/ProjectCard';
import CustomCursor from './components/CustomCursor';
import AnimatedBackground from './components/AnimatedBackground';
import AiChat from './components/AiChat';
import { ChevronDown, CandlestickChart, Sparkles, FolderCode, ArrowLeft, Radar } from 'lucide-react';
import { RadarChart, PolarGrid, PolarAngleAxis, PolarRadiusAxis, Radar as RechartsRadar, ResponsiveContainer } from 'recharts';

interface FadeInProps {
  isActive: boolean;
  delay?: number;
  className?: string;
  children: React.ReactNode;
}

const FadeIn: React.FC<FadeInProps> = ({ 
  isActive, 
  delay = 0, 
  className = "", 
  children 
}) => (
  <div 
    className={`transition-all duration-1000 ease-out transform ${
      isActive 
        ? 'opacity-100 translate-y-0 blur-0' 
        : 'opacity-0 translate-y-12 blur-sm'
    } ${className}`}
    style={{ transitionDelay: `${delay}ms` }}
  >
    {children}
  </div>
);

const App: React.FC = () => {
  const [viewMode, setViewMode] = useState<'main' | 'projects'>('main');
  const [activeSection, setActiveSection] = useState<string>('');
  const scrollContainerRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (viewMode === 'main') {
      if (scrollContainerRef.current) {
        scrollContainerRef.current.scrollTo(0, 0);
      }
      window.scrollTo(0, 0);

      const timer = setTimeout(() => {
        setActiveSection(SECTIONS[0].id);
      }, 100);
      return () => clearTimeout(timer);
    }
  }, [viewMode]);

  useEffect(() => {
    if (viewMode !== 'main') return;

    const container = scrollContainerRef.current;
    if (!container) return;

    const observer = new IntersectionObserver(
      (entries) => {
        entries.forEach((entry) => {
          if (entry.isIntersecting) {
            setActiveSection(entry.target.id);
          }
        });
      },
      {
        root: container,
        threshold: 0.3, 
      }
    );

    SECTIONS.forEach((section) => {
      const element = document.getElementById(section.id);
      if (element) observer.observe(element);
    });

    return () => {
      if (container) {
        observer.disconnect();
      }
    };
  }, [viewMode]);

  const handleNavigation = (id: string) => {
    if (viewMode === 'projects') {
      setViewMode('main');
      setTimeout(() => {
        const element = document.getElementById(id);
        if (element && scrollContainerRef.current) {
          element.scrollIntoView({ behavior: 'auto' });
          setActiveSection(id);
        }
      }, 10);
    } else {
      const element = document.getElementById(id);
      if (element && scrollContainerRef.current) {
        element.scrollIntoView({ behavior: 'smooth' });
      }
    }
  };

  return (
    <div className="bg-dark-bg text-dark-text h-screen w-full relative overflow-hidden font-sans selection:bg-brand/30 selection:text-brand">

      <CustomCursor />
      <AnimatedBackground />

      {viewMode === 'main' && (
        <Navigation activeSection={activeSection} scrollToSection={handleNavigation} />
      )}

      <header className="fixed top-0 left-0 w-full px-4 md:px-6 py-4 z-40 flex justify-between md:justify-center items-center bg-dark-bg/30 backdrop-blur-sm border-b border-white/5">
        <div 
          className="flex items-center gap-3 group cursor-pointer md:absolute md:left-6"
          onClick={() => handleNavigation('personality')}
        >
          <div className="p-2 bg-white/5 rounded-lg border border-white/10 group-hover:border-brand/50 transition-colors duration-300 shrink-0">
            <CandlestickChart className="text-brand drop-shadow-glow-sm" size={20} />
          </div>
          <span className="text-lg font-bold tracking-tight text-white group-hover:text-brand transition-colors duration-300 hidden md:block">
            shou.trade
          </span>
        </div>

        <nav className="flex items-center gap-3 md:gap-6">
          {SECTIONS.map((section) => (
            <button
              key={section.id}
              onClick={() => handleNavigation(section.id)}
              className={`text-[11px] md:text-sm font-medium transition-all duration-300 whitespace-nowrap ${
                viewMode === 'main' && activeSection === section.id
                  ? 'text-brand scale-105'
                  : 'text-neutral-400 hover:text-brand'
              }`}
            >
              {section.label}
            </button>
          ))}

          <div className="h-4 w-px bg-white/10 mx-2"></div>

          <button
            onClick={() => setViewMode('projects')}
            className={`
              flex items-center gap-2 px-4 py-1.5 rounded-full border backdrop-blur-md shadow-[0_0_15px_rgba(0,0,0,0.3)] transition-all duration-300
              ${viewMode === 'projects'
                ? 'bg-brand/10 border-brand/50 text-brand shadow-[0_0_10px_rgba(34,211,238,0.2)]' 
                : 'bg-white/5 border-white/10 text-neutral-300 hover:border-brand/30 hover:text-white'
              }
            `}
          >
            <FolderCode size={14} />
            <span className="text-[11px] md:text-sm font-medium">Проекты</span>
          </button>
        </nav>
      </header>

      <main
        ref={scrollContainerRef}
        className={`h-full w-full overflow-y-scroll snap-y snap-mandatory scroll-smooth no-scrollbar relative z-10 ${viewMode === 'main' ? 'block' : 'hidden'}`}
      >
        <Section id="personality">
          <div className="flex flex-col items-center justify-center text-center z-10 max-w-4xl pt-10 md:pt-16">
            <FadeIn isActive={activeSection === 'personality'} delay={50}>
              <div className="flex items-center justify-center gap-2 mb-6 bg-white/5 px-3 py-1.5 rounded-full border border-white/10">
                <div className="relative flex h-2 w-2">
                  <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-green-400 opacity-75"></span>
                  <span className="relative inline-flex rounded-full h-2 w-2 bg-green-500 shadow-[0_0_8px_rgba(34,197,94,0.6)]"></span>
                </div>
                <span className="text-[10px] font-mono text-green-400 tracking-widest uppercase font-semibold">
                  Market Open
                </span>
              </div>
            </FadeIn>

            <FadeIn isActive={activeSection === 'personality'} delay={100}>
              <h1 className="text-5xl md:text-9xl font-black tracking-tighter mb-2 select-none">
                shou<span className="text-brand drop-shadow-glow">.trade</span>
              </h1>
            </FadeIn>

            <FadeIn isActive={activeSection === 'personality'} delay={300}>
              <p className="text-brand/80 font-mono text-sm md:text-base tracking-[0.5em] uppercase mb-6">
                Mentality
              </p>
            </FadeIn>

            <FadeIn isActive={activeSection === 'personality'} delay={500}>
              <div className="h-px w-24 bg-neutral-700 my-6 mx-auto" />
            </FadeIn>

            <FadeIn isActive={activeSection === 'personality'} delay={700}>
              <p className="text-xl md:text-2xl font-light text-neutral-300 tracking-wide">
                2+ года в <span className="font-medium text-white">Трейдинге</span>
              </p>
            </FadeIn>

            <FadeIn isActive={activeSection === 'personality'} delay={900}>
              <p className="mt-4 text-dark-muted max-w-md mx-auto">
                Дисциплина, терпение, риск менеджмент, самоконтроль, дистанция
              </p>
            </FadeIn>
          </div>

          <FadeIn isActive={activeSection === 'personality'} delay={1200} className="absolute bottom-10">
            <button 
              onClick={() => handleNavigation('experience')}
              className="animate-bounce text-dark-muted hover:text-brand transition-colors"
            >
              <ChevronDown size={32} />
            </button>
          </FadeIn>
        </Section>

        <Section id="experience">
          <div className="w-full max-w-6xl mx-auto z-10 grid grid-cols-1 md:grid-cols-2 gap-6 md:gap-12 items-center">
            <div className="order-2 md:order-1">
              <FadeIn isActive={activeSection === 'experience'} delay={100}>
                <h2 className="text-3xl md:text-6xl font-bold mb-6 md:mb-8 flex items-center gap-3">
                  <span className="w-1.5 h-8 md:w-2 md:h-12 bg-brand rounded-full shadow-[0_0_15px_rgba(34,211,238,0.8)]"></span>
                  Опыт
                </h2>
              </FadeIn>

              <div className="grid grid-cols-1 gap-3 md:gap-6 mb-8">
                {TRADING_STATS.map((stat, idx) => (
                  <FadeIn key={idx} isActive={activeSection === 'experience'} delay={300 + (idx * 150)}>
                    <div className="bg-dark-card/80 backdrop-blur-sm border border-neutral-800 p-4 rounded-xl hover:border-brand/30 transition-colors group">
                      <h3 className="text-dark-muted text-xs md:text-sm uppercase tracking-wider mb-1 group-hover:text-brand/80 transition-colors">{stat.label}</h3>
                      <p className="text-xl md:text-3xl font-bold text-white mb-1">{stat.value}</p>
                      <p className="text-xs md:text-sm text-neutral-500">{stat.description}</p>
                    </div>
                  </FadeIn>
                ))}
              </div>
            </div>

            <FadeIn isActive={activeSection === 'experience'} delay={600} className="order-1 md:order-2 w-full">
              <div className="h-[300px] md:h-[400px] w-full bg-dark-card/50 rounded-2xl border border-neutral-800 p-4 md:p-6 relative overflow-hidden backdrop-blur-sm flex flex-col">
                  <h3 className="text-sm md:text-lg font-mono text-brand mb-2 md:mb-4 flex items-center gap-2">
                    <Radar size={18} className="text-brand animate-pulse" />
                    Skill Radar
                  </h3>
                  <div className="flex-1 w-full min-h-0">
                     <ResponsiveContainer width="100%" height="100%">
                      <RadarChart cx="50%" cy="50%" outerRadius="75%" data={SKILL_DATA}>
                        <PolarGrid stroke="#262626" />
                        <PolarAngleAxis 
                          dataKey="subject" 
                          tick={{ fill: '#a3a3a3', fontSize: 11, fontWeight: 500 }}
                        />
                        <PolarRadiusAxis angle={30} domain={[0, 10]} tick={false} axisLine={false} />
                        <RechartsRadar
                          name="Skills"
                          dataKey="A"
                          stroke="#22d3ee"
                          strokeWidth={2}
                          fill="#22d3ee"
                          fillOpacity={0.3}
                        />
                      </RadarChart>
                    </ResponsiveContainer>
                  </div>
              </div>
            </FadeIn>
          </div>
        </Section>

        <Section id="ai-chat">
          <div className="w-full max-w-4xl z-10 flex flex-col items-center">
            <FadeIn isActive={activeSection === 'ai-chat'} delay={100}>
              <div className="text-center mb-6 md:mb-8">
                <h2 className="text-3xl md:text-5xl font-bold mb-3 flex items-center justify-center gap-3">
                  <Sparkles className="text-brand" size={28} />
                  Ask the <span className="text-brand drop-shadow-glow">AI</span>
                </h2>
                <p className="text-dark-muted text-xs md:text-base max-w-md mx-auto px-4">
                  Анализ рыночных настроений или вопросы о трейдинге. На базе Gemini.
                </p>
              </div>
            </FadeIn>

            <FadeIn isActive={activeSection === 'ai-chat'} delay={300} className="w-full px-0 md:px-4">
              <AiChat />
            </FadeIn>
          </div>
        </Section>

        <Section id="connect">
          <div className="w-full max-w-4xl z-10 text-center">
            <FadeIn isActive={activeSection === 'connect'} delay={100}>
              <h2 className="text-4xl md:text-6xl font-bold mb-4">
                Контакты
              </h2>
            </FadeIn>

            <FadeIn isActive={activeSection === 'connect'} delay={200}>
              <p className="text-dark-muted mb-12 text-lg">
                Присоединяйся к сети. Следи за путем.
              </p>
            </FadeIn>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-4 text-left">
              {SOCIAL_LINKS.map((link, idx) => (
                <FadeIn key={link.name} isActive={activeSection === 'connect'} delay={400 + (idx * 100)}>
                  <SocialCard link={link} />
                </FadeIn>
              ))}
            </div>

            <FadeIn isActive={activeSection === 'connect'} delay={1000}>
              <footer className="mt-20 text-neutral-600 text-sm font-mono">
                © {new Date().getFullYear()} shou.trade. Все права защищены.
              </footer>
            </FadeIn>
          </div>
        </Section>
      </main>

      {/* === PROJECTS VIEW (SEPARATE PAGE) === */}
      {viewMode === 'projects' && (
        <div className="absolute inset-0 z-30 pt-24 px-4 md:px-8 pb-12 overflow-y-auto bg-dark-bg/95 backdrop-blur-xl animate-fade-in-up">
          <div className="w-full max-w-7xl mx-auto h-full flex flex-col">

            <div className="flex flex-col items-center mb-16 relative">
               <button 
                 onClick={() => setViewMode('main')}
                 className="absolute left-0 top-0 flex items-center text-neutral-400 hover:text-white transition-colors text-sm group"
               >
                 <ArrowLeft className="mr-2 transition-transform group-hover:-translate-x-1" size={18} />
                 Назад
               </button>

               <div className="text-center">
                  <h2 className="text-4xl md:text-6xl font-black tracking-tighter mb-4">
                    ПРОЕКТЫ
                  </h2>
                  <div className="h-1 w-20 bg-brand mx-auto rounded-full shadow-[0_0_15px_rgba(34,211,238,0.6)]" />
               </div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8 pb-24">
              {PROJECTS_DATA.map((project) => (
                <ProjectCard key={project.id} project={project} />
              ))}
            </div>
          </div>
        </div>
      )}

    </div>
  );
};

