export default async function handler(req, res) {
  // CORS Настройки
  res.setHeader('Access-Control-Allow-Credentials', true);
  res.setHeader('Access-Control-Allow-Origin', '*');
  res.setHeader('Access-Control-Allow-Methods', 'GET,OPTIONS,PATCH,DELETE,POST,PUT');
  res.setHeader(
    'Access-Control-Allow-Headers',
    'X-CSRF-Token, X-Requested-With, Accept, Accept-Version, Content-Length, Content-MD5, Content-Type, Date, X-Api-Version'
  );

  if (req.method === 'OPTIONS') {
    res.status(200).end();
    return;
  }

  if (req.method !== 'POST') {
    res.status(405).json({ error: 'Метод не поддерживается' });
    return;
  }

  try {
    const { messages } = req.body;

    // Формируем историю для Gemini
    const contents = messages.map(msg => ({
      role: msg.role === 'model' ? 'model' : 'user',
      parts: [{ text: msg.text }]
    }));

    const apiKey = process.env.VITE_API_KEY || process.env.API_KEY;

    if (!apiKey) {
       res.status(500).json({ error: 'Конфигурация сервера: отсутствует API ключ' });
       return;
    }

    // Системная инструкция для Shou AI
    const systemInstruction = {
      parts: [{
        text: `Ты — Shou AI, специализированный ассистент трейдера Shou. 
Твои правила:
1. Темы: Трейдинг, крипта, финансы, психология рынка, Smart Money, Price Action.
2. На посторонние темы (быт, еда, политика) отвечать ЗАПРЕЩЕНО. Вежливо напомни о своей специализации.
3. Стиль: Профессиональный, лаконичный, дисциплинированный.
4. Язык: Всегда отвечай на русском.
5. Не давай финансовых советов, только аналитику и обучение.`
      }]
    };

    // Запрос к Google API через сервер (Vercel), что позволяет обходить блокировку в РФ
    const response = await fetch(`https://generativelanguage.googleapis.com/v1beta/models/gemini-3-flash-preview:generateContent?key=${apiKey}`, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        // Мы не пробрасываем X-Forwarded-For, чтобы Google видел IP сервера Vercel, а не пользователя из РФ
      },
      body: JSON.stringify({
        systemInstruction: systemInstruction,
        contents: contents,
        generationConfig: {
            temperature: 0.7,
            topK: 40,
            topP: 0.95,
            maxOutputTokens: 1024,
        }
      })
    });

    const data = await response.json();

    if (!response.ok) {
        console.error("Google API Error:", data);
        res.status(response.status).json({ 
            error: data.error?.message || 'Ошибка API Google',
            details: data 
        });
        return;
    }

    res.status(200).json(data);

  } catch (error) {
    console.error("Proxy Crash:", error);
    res.status(500).json({ error: 'Внутренняя ошибка прокси-сервера' });
  }
}

import React, { useState, useRef, useEffect } from 'react';
import { Send, Bot, User, AlertTriangle, Loader2 } from 'lucide-react';

interface Message {
  role: 'user' | 'model';
  text: string;
  isError?: boolean;
}

const AiChat: React.FC = () => {
  const [messages, setMessages] = useState<Message[]>([
    { role: 'model', text: 'Личность: Shou AI. Я работаю через защищенный прокси, поэтому VPN вам не нужен. Задавайте вопросы по трейдингу.' }
  ]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);

  const chatContainerRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    scrollToBottom();
  }, [messages, isLoading]);

  const scrollToBottom = () => {
    if (chatContainerRef.current) {
      chatContainerRef.current.scrollTop = chatContainerRef.current.scrollHeight;
    }
  };

  const handleSend = async () => {
    if (!input.trim() || isLoading) return;

    const userMessage = input;
    setInput('');
    setMessages(prev => [...prev, { role: 'user', text: userMessage }]);
    setIsLoading(true);

    try {
      // Работаем ТОЛЬКО через прокси. Прямое обращение к Google в РФ заблокировано.
      const response = await fetch('/api/chat', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ 
            messages: [...messages, { role: 'user', text: userMessage }] 
        }),
      });

      if (!response.ok) {
         const errData = await response.json().catch(() => ({}));
         throw new Error(errData.error || `Ошибка сервера: ${response.status}`);
      }

      const data = await response.json();
      const text = data.candidates?.[0]?.content?.parts?.[0]?.text;

      if (!text) throw new Error("Получен пустой ответ от ИИ.");

      setMessages(prev => [...prev, { role: 'model', text: text }]);

    } catch (error: any) {
      console.error("Chat Error:", error);

      let errorMessage = "Произошла ошибка при связи с ИИ.";

      if (error.message.includes('403')) {
          errorMessage = "Доступ заблокирован. Попробуйте позже или проверьте статус сервера.";
      } else if (error.message.includes('fetch')) {
          errorMessage = "Ошибка сети. Проверьте интернет-соединение.";
      } else {
          errorMessage = error.message;
      }

      setMessages(prev => [...prev, { 
        role: 'model', 
        text: `ОШИБКА: ${errorMessage}`, 
        isError: true 
      }]);
    } finally {
      setIsLoading(false);
    }
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSend();
    }
  };

  return (
    <div className="w-full max-w-3xl mx-auto h-[60vh] md:h-[500px] flex flex-col bg-black/40 backdrop-blur-md rounded-2xl border border-white/10 overflow-hidden shadow-[0_0_40px_rgba(34,211,238,0.05)]">
      {/* Messages Area */}
      <div 
        ref={chatContainerRef}
        className="flex-1 overflow-y-auto p-4 md:p-6 space-y-6 scroll-smooth custom-scrollbar mt-2"
      >
        {messages.map((msg, idx) => (
          <div 
            key={idx} 
            className={`flex gap-3 md:gap-4 ${msg.role === 'user' ? 'flex-row-reverse' : 'flex-row'}`}
          >
            <div className={`flex-shrink-0 w-8 h-8 rounded-full flex items-center justify-center ${
              msg.role === 'user' 
                ? 'bg-neutral-800 text-neutral-400' 
                : msg.isError ? 'bg-red-500/20 text-red-500' : 'bg-brand/20 text-brand'
            }`}>
              {msg.role === 'user' ? <User size={14} /> : msg.isError ? <AlertTriangle size={14}/> : <Bot size={14} />}
            </div>
            <div className={`max-w-[85%] p-3 md:p-4 rounded-2xl text-xs md:text-sm leading-relaxed ${
              msg.role === 'user'
                ? 'bg-neutral-900 text-neutral-200 rounded-tr-sm'
                : msg.isError
                  ? 'bg-red-500/10 text-red-400 border border-red-500/20 rounded-tl-sm font-mono text-[10px]'
                  : 'bg-brand/5 text-brand/90 border border-brand/10 rounded-tl-sm shadow-[0_0_15px_rgba(34,211,238,0.05)]'
            }`}>
              {msg.text}
            </div>
          </div>
        ))}
        {isLoading && (
            <div className="flex gap-4">
                 <div className="flex-shrink-0 w-8 h-8 rounded-full bg-brand/20 text-brand flex items-center justify-center">
                    <Bot size={14} />
                </div>
                <div className="bg-brand/5 border border-brand/10 p-4 rounded-2xl rounded-tl-sm flex items-center gap-3">
                     <div className="w-1.5 h-1.5 bg-brand/50 rounded-full animate-bounce" style={{ animationDelay: '0ms' }}/>
                     <div className="w-1.5 h-1.5 bg-brand/50 rounded-full animate-bounce" style={{ animationDelay: '150ms' }}/>
                     <div className="w-1.5 h-1.5 bg-brand/50 rounded-full animate-bounce" style={{ animationDelay: '300ms' }}/>
                </div>
            </div>
        )}
      </div>

      {/* Input Area */}
      <div className="p-4 bg-black/20 border-t border-white/5">
        <div className="relative flex items-center gap-2">
            <input
                type="text"
                value={input}
                onChange={(e) => setInput(e.target.value)}
                onKeyDown={handleKeyDown}
                placeholder="Спроси о рынке (без VPN)..."
                className="w-full bg-neutral-900/50 text-white text-sm rounded-xl pl-4 pr-12 py-3 md:py-4 focus:outline-none focus:ring-1 focus:ring-brand/50 transition-all placeholder:text-neutral-600"
                disabled={isLoading}
            />
            <button 
                onClick={handleSend}
                disabled={!input.trim() || isLoading}
                className="absolute right-2 p-2 bg-brand text-black rounded-lg hover:bg-white transition-colors disabled:opacity-50 disabled:cursor-not-allowed"
            >
                {isLoading ? <Loader2 size={16} className="animate-spin" /> : <Send size={16} />}
            </button>
        </div>
        <p className="text-[9px] text-center text-neutral-600 mt-2 font-mono uppercase tracking-widest">
            Proxied via Vercel Edge • No VPN Required
        </p>
      </div>
    </div>
  );
};

