import React, { useState, useRef, useEffect } from 'react';
import { Send, Bot, User, AlertTriangle, Loader2 } from 'lucide-react';

interface Message {
  role: 'user' | 'model';
  text: string;
  isError?: boolean;
}

const AiChat: React.FC = () => {
  const [messages, setMessages] = useState<Message[]>([
    { role: 'model', text: 'Личность: Shou AI. Задавайте вопросы по трейдингу, анализу рынков или психологии торговли.' }
  ]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);

  const chatContainerRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    scrollToBottom();
  }, [messages, isLoading]);

  const scrollToBottom = () => {
    if (chatContainerRef.current) {
      chatContainerRef.current.scrollTop = chatContainerRef.current.scrollHeight;
    }
  };

  const handleSend = async () => {
    if (!input.trim() || isLoading) return;

    const userMessage = input;
    setInput('');
    setMessages(prev => [...prev, { role: 'user', text: userMessage }]);
    setIsLoading(true);

    try {
      const response = await fetch('/api/chat', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ 
            messages: [...messages, { role: 'user', text: userMessage }] 
        }),
      });

      if (!response.ok) {
         const errData = await response.json().catch(() => ({}));
         throw new Error(errData.error || `Ошибка сервера: ${response.status}`);
      }

      const data = await response.json();
      const text = data.candidates?.[0]?.content?.parts?.[0]?.text;

      if (!text) throw new Error("Получен пустой ответ от ИИ.");

      setMessages(prev => [...prev, { role: 'model', text: text }]);

    } catch (error: any) {
      console.error("Chat Error:", error);

      let errorMessage = "Произошла ошибка при связи с ИИ.";

      if (error.message.includes('403')) {
          errorMessage = "Доступ временно ограничен. Попробуйте позже.";
      } else if (error.message.includes('fetch')) {
          errorMessage = "Ошибка сети. Проверьте интернет-соединение.";
      } else {
          errorMessage = error.message;
      }

      setMessages(prev => [...prev, { 
        role: 'model', 
        text: `ОШИБКА: ${errorMessage}`, 
        isError: true 
      }]);
    } finally {
      setIsLoading(false);
    }
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSend();
    }
  };

  return (
    <div className="w-full max-w-3xl mx-auto h-[55vh] md:h-[500px] flex flex-col bg-black/40 backdrop-blur-md rounded-2xl md:rounded-3xl border border-white/10 overflow-hidden shadow-2xl">
      {/* Messages Area */}
      <div 
        ref={chatContainerRef}
        className="flex-1 overflow-y-auto p-4 md:p-6 space-y-4 md:space-y-6 scroll-smooth custom-scrollbar"
      >
        {messages.map((msg, idx) => (
          <div 
            key={idx} 
            className={`flex gap-3 md:gap-4 ${msg.role === 'user' ? 'flex-row-reverse' : 'flex-row'}`}
          >
            <div className={`flex-shrink-0 w-7 h-7 md:w-8 md:h-8 rounded-full flex items-center justify-center ${
              msg.role === 'user' 
                ? 'bg-neutral-800 text-neutral-400' 
                : msg.isError ? 'bg-red-500/20 text-red-500' : 'bg-brand/20 text-brand'
            }`}>
              {msg.role === 'user' ? <User size={12} /> : msg.isError ? <AlertTriangle size={12}/> : <Bot size={12} />}
            </div>
            <div className={`max-w-[88%] md:max-w-[85%] p-3 md:p-4 rounded-xl md:rounded-2xl text-[11px] md:text-sm leading-relaxed ${
              msg.role === 'user'
                ? 'bg-neutral-900 text-neutral-200 rounded-tr-sm'
                : msg.isError
                  ? 'bg-red-500/10 text-red-400 border border-red-500/20 rounded-tl-sm'
                  : 'bg-brand/5 text-brand/90 border border-brand/10 rounded-tl-sm'
            }`}>
              {msg.text}
            </div>
          </div>
        ))}
        {isLoading && (
            <div className="flex gap-3 md:gap-4">
                 <div className="flex-shrink-0 w-7 h-7 md:w-8 md:h-8 rounded-full bg-brand/20 text-brand flex items-center justify-center">
                    <Bot size={12} />
                </div>
                <div className="bg-brand/5 border border-brand/10 px-3 py-2.5 rounded-xl rounded-tl-sm flex items-center gap-2">
                     <div className="w-1 h-1 bg-brand/50 rounded-full animate-bounce" style={{ animationDelay: '0ms' }}/>
                     <div className="w-1 h-1 bg-brand/50 rounded-full animate-bounce" style={{ animationDelay: '150ms' }}/>
                     <div className="w-1 h-1 bg-brand/50 rounded-full animate-bounce" style={{ animationDelay: '300ms' }}/>
                </div>
            </div>
        )}
      </div>

      {/* Input Area */}
      <div className="p-3 md:p-4 bg-black/40 border-t border-white/5">
        <div className="relative flex items-center gap-2">
            <input
                type="text"
                value={input}
                onChange={(e) => setInput(e.target.value)}
                onKeyDown={handleKeyDown}
                placeholder="Спроси о рынке..."
                className="w-full bg-neutral-900/80 text-white text-[11px] md:text-sm rounded-xl md:rounded-2xl pl-4 pr-12 py-3 md:py-4 focus:outline-none focus:ring-1 focus:ring-brand/50 transition-all placeholder:text-neutral-600"
                disabled={isLoading}
            />
            <button 
                onClick={handleSend}
                disabled={!input.trim() || isLoading}
                className="absolute right-1.5 md:right-2 p-2 md:p-2.5 bg-brand text-black rounded-lg md:rounded-xl hover:bg-white transition-colors disabled:opacity-30"
            >
                {isLoading ? <Loader2 size={14} className="animate-spin" /> : <Send size={14} />}
            </button>
        </div>
      </div>
    </div>
  );
};

